package com.blissless.tensei.ui.screens.playerimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.layout.Arrangementimport androidx.compose.foundation.layout.Boximport androidx.compose.foundation.layout.Rowimport androidx.compose.foundation.layout.fillMaxWidthimport androidx.compose.foundation.layout.paddingimport androidx.compose.foundation.layout.sizeimport androidx.compose.foundation.shape.RoundedCornerShapeimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.filled.Checkimport androidx.compose.material3.DropdownMenuItemimport androidx.compose.material3.Iconimport androidx.compose.material3.MaterialThemeimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.unit.dp@Composablefun ServerSelectorButton(    serverName: String,    isSelected: Boolean,    onClick: () -> Unit) {    DropdownMenuItem(        text = {            Row(                modifier = Modifier.fillMaxWidth()                    .background(                        if (isSelected) MaterialTheme.colorScheme.primary.copy(alpha = 0.15f) else Color.Transparent,                        RoundedCornerShape(4.dp)                    )                    .padding(horizontal = 8.dp, vertical = 4.dp),                verticalAlignment = Alignment.CenterVertically,                horizontalArrangement = Arrangement.spacedBy(8.dp)            ) {                if (isSelected) Icon(                    Icons.Default.Check,                    null,                    tint = MaterialTheme.colorScheme.primary,                    modifier = Modifier.size(16.dp)                )                Text(                    serverName.uppercase(),                    color = if (isSelected) MaterialTheme.colorScheme.primary else Color.White                )            }        },        onClick = onClick    )}